SELECT qna_admin_id AS qnaAdminId, NULL AS qnaId, title, content, status, answer, created_at AS createdAt, answered_at AS answeredAt, '관리자' AS qnaType, NULL AS programId, NULL AS programTitle FROM qna_admin WHERE user_id = #{userId}
UNION ALL
SELECT NULL AS qnaAdminId, q.qna_id AS qnaId, q.title, q.content, q.status, q.answer, q.created_at AS createdAt, q.answered_at AS answeredAt, '공방' AS qnaType, p.program_id AS programId, p.title AS programTitle FROM qna_workshop AS q JOIN program AS p ON q.program_id = p.program_id WHERE q.user_id = #{userId}
ORDER BY createdAt DESC
